public String createHistoryTitleRow(RagicBundle bundle) {
	return "<tr>" +
            "<th>"+bundle.getString("fieldHistory_header_modiyTime")+"</th>" +
            "<th>"+bundle.getString("fieldHistory_header_modifyUser")+"</th>" +
            "<th>"+bundle.getString("fieldHistory_header_modifySheet")+"</th>" +
            "<th>"+bundle.getString("fieldHistory_header_modifyChanges")+"</th>" +
            "<th>"+bundle.getString("fieldHistory_header_modifyTriggerInfo")+"</th>" +
            "</tr>";
}
private String getDisplayedChange(JSONArray fromValue, JSONArray toValue, RagicBundle bundle) {
	String change = "";
	if(fromValue.length() > 1 || toValue.length() > 1) {
		change = fromValue.toString()+" <i class='far fa-arrow-right'></i> "+toValue.toString();
	} else {
		if(fromValue.length() == 0) {
			change += "<span style='color:#ccc;'>"+bundle.getString("empty")+"</span>";
		} else {
			change += Encoder.encjs(fromValue.optString(0).replace("\r\n", "\n").replace("\n", "\r\n"), true); //issue#13952
		}
		change += " <i class='far fa-arrow-right'></i> ";
		if(toValue.length() == 0) {
			change += "<span style='color:#ccc;'>"+bundle.getString("empty")+"</span>";
		} else {
			change += Encoder.encjs(toValue.optString(0).replace("\r\n", "\n").replace("\n", "\r\n"), true); //issue#13952
		}
	}
    return change;
}
public String formatHistory(Date date, String email, String userName, String sheetName, String change, String triggerInfo) {
    return "<tr>" +
            "<td>"+Encoder.formatAsStandardDate(date,true)+"</td>" +
            "<td><a href='mailto:"+email+"'>"+userName+"</a></td>" +
            "<td>" + sheetName + "</td>" +
            "<td>"+change+"</td>" +
            "<td>"+triggerInfo+"</td>" +
            "</tr>";
}

private Optional<NUIForm> getUpdatedForm(String apname, JSONObject summaryFeed) {
	Optional<NUIForm> updatedForm = Optional.empty();
	
	String updatedFormUrl = summaryFeed.optString("url", null);
    if(updatedFormUrl == null) return updatedForm;
    String[] secs = updatedFormUrl.split("\\/");
    if(secs.length != 3) return updatedForm;
    updatedForm = Optional.ofNullable(AppManager.getFormPage(apname, "/" + secs[1], Encoder.parseInt(secs[2], -1), true));
	return updatedForm;
}
private JSONArray formatDisplayFileName(JSONArray rawValues) throws JSONException {
    JSONArray formattedValues = new JSONArray();
    for(int i = 0; i < rawValues.length(); i++) {
        formattedValues.put(FileHelper.getFileNameFromFullFileLink(rawValues.getString(i)));
    }
    return formattedValues;
}

